87	    p_main : process
88	    begin
89	        test_runner_setup(runner, runner_cfg);
90	        
91	        while test_suite loop
92	            if run("test") then
93	                wait until (and finished) = '1';
94	            end if;
95	        end loop;
96	        
97	        print("SUCCESS! All tests passed.");
98	        test_runner_cleanup(runner);
99	    end process;
100	    
101	    -----------------------------------------------------------------------------------------------
102	    -- Test Cases
103	    -----------------------------------------------------------------------------------------------
104	    g_test_case : for i in 0 to test_count_c-1 generate
105	        constant RandSeed_c : string := "Metadata seed " & to_string(i);
106	        constant Amin       : integer := cl_fix_to_integer(cl_fix_min_value(a_fmt_c(i)), a_fmt_c(i));
107	        constant Amax       : integer := cl_fix_to_integer(cl_fix_max_value(a_fmt_c(i)), a_fmt_c(i));
108	        
109	        signal rst          : std_logic;
110	        
111	        signal in_valid     : std_logic;
112	        signal in_meta      : std_logic_vector(meta_width_g-1 downto 0);
113	        signal in_data      : std_logic_vector(cl_fix_width(a_fmt_c(i))-1 downto 0);
114	        
115	        signal out_valid    : std_logic;
116	        signal out_meta     : std_logic_vector(meta_width_g-1 downto 0);
117	        signal out_data     : std_logic_vector(cl_fix_width(r_fmt_c(i))-1 downto 0);
118	    begin
119	        -----------
120	        -- Input --
121	        -----------
122	        p_input : process
123	            variable Random_v   : RandomPType;
124	        begin
125	            Random_v.InitSeed(RandSeed_c);
126	            
127	            -- Reset
128	            rst <= '1';
129	            in_valid <= '0';
130	            wait until rising_edge(clk);
131	            rst <= '0';
132	            
133	            -- The cosim script generates all possible input values (counter).
134	            -- We repeat the same pattern here.
135	            for a in Amin to Amax loop
136	                in_valid <= '1';
137	                in_meta <= Random_v.RandSlv(meta_width_g);
138	                in_data <= cl_fix_from_integer(a, a_fmt_c(i));
139	                wait until rising_edge(clk);
140	            end loop;
141	            
142	            -- Idle
143	            in_valid <= '0';
144	            in_meta <= (others => 'X');
145	            in_data <= (others => 'X');
146	            wait;
147	        end process;
148	        
149	        ---------
150	        -- UUT --
151	        ---------
152	        i_uut : entity work.en_cl_fix_round
153	        generic map(
154	            in_fmt_g        => a_fmt_c(i),
155	            out_fmt_g       => r_fmt_c(i),
156	            round_g         => FixRound_t'val(rnd_c(i)),
157	            reg_mode_g      => RegisterMode_t'val(i mod reg_mode_count_c),  -- Toggle between test cases.
158	            meta_width_g    => meta_width_g
159	        )
160	        port map(
161	            -- Clock and Reset
162	            clk         => clk,
163	            rst         => rst,
164	            -- Input
165	            in_valid    => in_valid,
166	            in_meta     => in_meta,
167	            in_data     => in_data,
168	            -- Output
169	            out_valid   => out_valid,
170	            out_meta    => out_meta,
171	            out_data    => out_data
172	        );
