178	            constant Expected_c : SlvArray_t := cl_fix_read_file(DataPath_c & "test" & to_string(i) & "_output.txt", r_fmt_c(i));
179	            variable Idx_v      : natural := 0;
180	            variable Random_v   : RandomPType;
181	        begin
182	            Random_v.InitSeed(RandSeed_c);
183	            
184	            for a in Amin to Amax loop
185	                wait until out_valid = '1' and rising_edge(Clk);
186	                
187	                -- Check metadata
188	                check_equal(out_meta, Random_v.RandSlv(meta_width_g), "Metadata mismatch");
189	                
190	                -- Check data against cosim
191	                if out_data /= Expected_c(Idx_v) then
192	                    print(
193	                        "Error in test case " & to_string(i) & " while rounding " & str(a, a_fmt_c(i)) & " " & to_string(a_fmt_c(i))
194	                        & " [rnd: " & to_string(FixRound_t'val(rnd_c(i))) & "] --> " & to_string(r_fmt_c(i))
195	                    );
196	                    check_equal(out_data, Expected_c(Idx_v), "Error at index " & to_string(Idx_v));
197	                end if;
198	                
199	                Idx_v := Idx_v + 1;
200	            end loop;
201	            
202	            finished(i) <= '1';
203	        end process;
204	    end generate;
205	end rtl;
