20	---------------------------------------------------------------------------------------------------
21	-- Description:
22	--
23	-- File I/O support for en_cl_fix.
24	--
25	-- This package provides wrappers around en_tb.en_tb_fileio_text_pkg for en_cl_fix.
26	--
27	-- A short summary is provided for quick reference:
28	--
29	-- ================================================================================================
30	-- Data Reading
31	-- ================================================================================================
32	--     ------------------------------
33	--     Read data from std.textio.line
34	--     ------------------------------
35	--         cl_fix_read(L, x, fmt, [mode])
36	--     ------------------------------
37	--     Read data from std.textio.text
38	--     ------------------------------
39	--         x := cl_fix_read(f, fmt, [mode], [skip_before], [close_after])
40	--     --------------------
41	--     Read whole data file
42	--     --------------------
43	--         x := cl_fix_read_file(filename, fmt, [mode], [skip])
44	-- ================================================================================================
45	-- FixFormat_t Reading
46	-- ================================================================================================
47	--     -------------------------------------
48	--     Read FixFormat_t from std.textio.line
49	--     -------------------------------------
50	--         cl_fix_read_format(L, fmt)
51	--     -------------------------------------
52	--     Read FixFormat_t from std.textio.text
53	--     -------------------------------------
54	--         fmt := cl_fix_read_format(f, [skip_before], [close_after])
55	--     ---------------------------
56	--     Read whole FixFormat_t file
57	--     ---------------------------
58	--         fmt := cl_fix_read_format_file(filename, [skip])
59	-- ================================================================================================
60	-- Data Writing
61	-- ================================================================================================
62	--     -----------------------------
63	--     Write data to std.textio.line
64	--     -----------------------------
65	--         cl_fix_write(L, x, fmt, [mode])
66	--     -----------------------------
67	--     Write data to std.textio.text
68	--     -----------------------------
69	--         cl_fix_write(f, x, fmt, [mode])
70	--     ---------------------
71	--     Write whole data file
72	--     ---------------------
73	--         cl_fix_write_file(filename, x, fmt, [mode], [header])
74	-- ================================================================================================
75	-- FixFormat_t Writing
76	-- ================================================================================================
77	--     ------------------------------------
78	--     Write FixFormat_t to std.textio.line
79	--     ------------------------------------
80	--         cl_fix_write_format(L, fmt)
81	--     ------------------------------------
82	--     Write FixFormat_t to std.textio.text
83	--     ------------------------------------
84	--         cl_fix_write_format(f, fmt)
85	--     ----------------------------
86	--     Write whole FixFormat_t file
87	--     ----------------------------
88	--         cl_fix_write_format_file(filename, fmts)
89	--
90	---------------------------------------------------------------------------------------------------
91	
92	---------------------------------------------------------------------------------------------------
93	-- Libraries
94	---------------------------------------------------------------------------------------------------
95	library std;
96	    use std.textio.all;
97	
98	library ieee;
99	    use ieee.std_logic_1164.all;
100	
101	library en_tb;
102	    use en_tb.en_tb_base_pkg.all;
103	    use en_tb.en_tb_fileio_text_pkg.all;
104	
105	library work;
106	    use work.en_cl_fix_pkg.all;
107	
108	---------------------------------------------------------------------------------------------------
109	-- Package
110	---------------------------------------------------------------------------------------------------
111	package en_cl_fix_fileio_pkg is
112	    
113	    -----------------------------------------------------------------------------------------------
114	    -- Read Access
115	    -----------------------------------------------------------------------------------------------
116	    
117	    -----------------------------------------
118	    -- Read EN_CL_FIX Data From Text Files --
119	    -----------------------------------------
120	    
121	    -- Parse ASCII text line as a single fixed-point value
122	    procedure cl_fix_read(
123	        variable L          : inout line;
124	        variable Data       : out   ieee.std_logic_1164.std_logic_vector;
125	        constant Fmt        : in    FixFormat_t;
126	        constant TextMode   : in    text_data_mode_t := ascii_dec
127	    );
128	    
129	    -- Read a single fixed-point value from a single-column ASCII text file
130	    impure function cl_fix_read(
131	        file     F          : text;
132	        constant Fmt        : FixFormat_t;
133	        constant TextMode   : text_data_mode_t := ascii_dec;
134	        constant SkipBefore : natural := 0;
135	        constant CloseAfter : boolean := false
136	    ) return std_logic_vector;
137	    
138	    -- Read a whole text file containing fixed-point data
139	    impure function cl_fix_read_file(
140	        constant Filename   : in string;
141	        constant Fmt        : in FixFormat_t;
142	        constant TextMode   : in text_data_mode_t := ascii_dec;
143	        constant SkipLines  : in natural := 1
144	    ) return SlvArray_t;
145	    
146	    ------------------------------------------------
147	    -- Read EN_CL_FIX FixFormat_t From Text Files --
148	    ------------------------------------------------
149	    
150	    -- Parse ASCII text line as a single FixFormat_t
151	    procedure cl_fix_read_format(
152	        variable L          : inout line;
153	        variable Fmt        : out   FixFormat_t
154	    );
155	    
156	    -- Read a single FixFormat_t from a single-column ASCII text file
157	    impure function cl_fix_read_format(
158	        file F              : text;
159	        constant SkipBefore : natural := 0;
160	        constant CloseAfter : boolean := false
161	    ) return FixFormat_t;
162	    
163	    -- Read a whole text file containing a single column of FixFormat_t strings
164	    impure function cl_fix_read_format_file(
165	        constant Filename   : in string;
166	        constant SkipLines  : in natural := 1
167	    ) return FixFormatArray_t;
168	    
169	    -----------------------------------------------------------------------------------------------
170	    -- Write Access
171	    -----------------------------------------------------------------------------------------------
172	    
173	    ----------------------------------------
174	    -- Write EN_CL_FIX Data To Text Files --
175	    ----------------------------------------
176	    
177	    -- Write a single fixed-point value to a text line
178	    procedure cl_fix_write(
179	        variable L          : inout line;
180	        constant Data       : in    std_logic_vector;
181	        constant Fmt        : in    FixFormat_t;
182	        constant TextMode   : in    text_data_mode_t := ascii_dec
183	    );
184	    
185	    -- Write a single fixed-point value to a text file
186	    procedure cl_fix_write(
187	        file     F          : text;
188	        constant Data       : in    std_logic_vector;
189	        constant Fmt        : in    FixFormat_t;
190	        constant TextMode   : in    text_data_mode_t := ascii_dec
191	    );
192	    
193	    -- Write a whole text file of fixed-point data
194	    procedure cl_fix_write_file(
195	        constant Filename   : in  string;
196	        constant Data       : in  SlvArray_t;
197	        constant Fmt        : in  FixFormat_t;
198	        constant TextMode   : in  text_data_mode_t := ascii_dec;
199	        constant Header     : in  string := ""
200	    );
201	    
202	    -----------------------------------------------
203	    -- Write EN_CL_FIX FixFormat_t To Text Files --
204	    -----------------------------------------------
205	    
206	    -- Write a single FixFormat_t to a text line
207	    procedure cl_fix_write_format(
208	        variable L          : inout line;
209	        constant Fmt        : in FixFormat_t
210	    );
211	    
212	    -- Write a single FixFormat_t to a text file
213	    procedure cl_fix_write_format(
214	        file F          : text;
215	        constant Fmt    : in FixFormat_t
216	    );
217	    
218	    -- Write an array of FixFormat_t strings to a text file
219	    procedure cl_fix_write_format_file(
220	        constant Filename   : in string;
221	        constant Formats    : in FixFormatArray_t
222	    );
223	    
224	end package;
225	
226	---------------------------------------------------------------------------------------------------
227	-- Package Body
228	---------------------------------------------------------------------------------------------------
229	package body en_cl_fix_fileio_pkg is
230	    
231	    -----------------------------------------------------------------------------------------------
232	    -- Private Functions
233	    -----------------------------------------------------------------------------------------------
234	    
235	    -- Helper function to determine Signedness_t from FixFormat_t
236	    function cl_fix_to_signedness(constant Fmt : in FixFormat_t) return Signedness_t is
237	    begin
238	        if Fmt.S = 1 then
239	            return Signed_s;
240	        else
241	            return Unsigned_s;
242	        end if;
243	    end function;
244	    
245	    -----------------------------------------------------------------------------------------------
246	    -- Read Access
247	    -----------------------------------------------------------------------------------------------
248	    
249	    -----------------------------------------
250	    -- Read EN_CL_FIX Data From Text Files --
251	    -----------------------------------------
252	    
253	    -- Parse ASCII text line as a single fixed-point value
254	    procedure cl_fix_read(
255	        variable L          : inout line;
256	        variable Data       : out   ieee.std_logic_1164.std_logic_vector;
257	        constant Fmt        : in    FixFormat_t;
258	        constant TextMode   : in    text_data_mode_t := ascii_dec
