47	
48	architecture sim of en_cl_fix_pkg_tb is
49	    
50	    procedure check_equal(got, expected : FixFormat_t; msg : string) is
51	    begin
52	        assert got = expected report msg & ", got: " & to_string(got) & ", expected: " & to_string(expected) severity Failure;
53	    end procedure;
54	    
55	begin
56	    
57	    test_runner_watchdog(runner, 100 ms);
