59	    ----------------
60	    -- VUnit Main --
61	    ----------------
62	    p_main : process
63	    begin
64	        test_runner_setup(runner, runner_cfg);
65	        
66	        while test_suite loop
67	            if run("test") then
68	                -- cl_fix_add_fmt
69	                print("cl_fix_add_fmt");
70	                check_equal(cl_fix_add_fmt((1, 1, 1), (0, 7, 0)), (1, 8, 1), "cl_fix_add_fmt Wrong");
71	                
72	                -- cl_fix_sub_fmt
