94	                check_equal(cl_fix_width((0, 3, 0)), 3, "cl_fix_width Wrong: Integer only, Unsigned, NoFractional Bits");
95	                check_equal(cl_fix_width((1, 3, 0)), 4, "cl_fix_width Wrong: Integer only, Signed, NoFractional Bits");
96	                check_equal(cl_fix_width((0, 0, 3)), 3, "cl_fix_width Wrong: Fractional only, Unsigned, No Integer Bits");
97	                check_equal(cl_fix_width((1, 0, 3)), 4, "cl_fix_width Wrong: Fractional only, Signed, No Integer Bits");
