20	---------------------------------------------------------------------------------------------------
21	-- Description:
22	--
23	-- Text file reading and writing.
24	--
25	-- The text files can contain numbers in any supported base:
26	--     text_data_mode_t is (ascii_bin, ascii_dec, ascii_hex)
27	--
28	-- Many VHDL data types are supported. For non-numeric types (e.g. std_logic_vector), it is
29	-- required to explicitly specify the signedness of the numbers in the file:
30	--     Signedness_t is (Unsigned_s, Signed_s);
31	--
32	-- Important: This file is very verbose. We tried to use VHDL-2008 generic subprograms to make it
33	-- more concise, but simulator support was extremely weak (in all of: Modelsim, Questa and GHDL).
34	--
35	-- A short summary is provided for quick reference:
36	--
37	-- ================================================================================================
38	-- Read Access
39	-- ================================================================================================
40	--     -------------------------------
41	--     Read value from std.textio.line
42	--     -------------------------------
43	--         Numeric types:
44	--             read(L, x, [mode])
45	--         Non-numeric types:
46	--             read(L, x, signedness, [mode])
47	--     -------------------------------
48	--     Read value from std.textio.text
49	--     -------------------------------
50	--         Numeric types:
51	--             read(f, x, [mode], [skip_before], [close_after])
52	--             x := read(f, n_bits, [mode], [skip_before], [close_after])
53	--         Non-numeric types:
54	--             read(f, x, signedness, [mode], [skip_before], [close_after])
55	--             x := read(f, n_bits, signedness, [mode], [skip_before], [close_after])
56	--     ---------------
57	--     Read whole file
58	--     ---------------
59	--         Numeric types:
60	--             x := read_file(filename, n_bits, [mode], [skip])
61	--         Non-numeric types:
62	--             x := read_file(filename, n_bits, signedness, [mode], [skip])
63	--
64	-- ================================================================================================
65	-- Write Access
66	-- ================================================================================================
67	--     ------------------------------
68	--     Write value to std.textio.line
69	--     ------------------------------
70	--         Numeric types:
71	--             write(L, x, [mode])
72	--         Non-numeric types:
73	--             write(L, x, signedness, [mode])
74	--     ------------------------------
75	--     Write value to std.textio.text
76	--     ------------------------------
77	--         Numeric types:
78	--             write(f, x, [mode])
79	--         Non-numeric types:
80	--             write(f, x, signedness, [mode])
81	--     ----------------
82	--     Write whole file
83	--     ----------------
84	--         Numeric types:
85	--             write_file(filename, x, [mode], [header])
86	--         Non-numeric types:
87	--             write_file(filename, x, signedness, [mode], [header])
88	---------------------------------------------------------------------------------------------------
89	
90	---------------------------------------------------------------------------------------------------
91	-- Libraries
92	---------------------------------------------------------------------------------------------------
93	library std;
94	    use std.textio.all;
