568	    -----------------------------------------------------------------------------------------------
569	    -- File Utility Functions
570	    -----------------------------------------------------------------------------------------------
571	    
572	    -- Skip n lines in a file
573	    procedure skip_lines(file f : text; n : natural) is
574	        variable line_v : line;
575	    begin
576	        for i in 0 to n-1 loop
577	            readline(f, line_v);
578	        end loop;
579	        deallocate(line_v);
580	    end;
581	    
582	    -- Get file size in lines. (Useful for ASCII files)
583	    -- Warning! This function iterates through the whole file, so avoid using for large files.
584	    impure function get_file_size_lines(filename : string) return integer is
585	        file f      : text;
586	        variable n  : integer := 0;
587	        variable L  : line;
588	    begin
589	        file_open(f, filename, read_mode);
590	        while not endfile(f) loop
591	            readline(f, L);
592	            n := n + 1;
593	        end loop;
594	        file_close(f);
595	        deallocate(L);
596	        return n;
597	    end function;
598	    
599	    -- Get file size in columns.
600	    -- Note: This only checks the first line and assumes all others are the same
601	    impure function get_file_size_columns(
602	        filename    : string;
603	        skip        : natural := 1;
604	        mode        : text_data_mode_t := ascii_dec
605	    ) return integer is
606	        file f      : text;
607	        variable L  : line;
608	        
609	        -- Nested helper function to deallocate line before returning string
610	        impure function get_string return string is
611	            constant s  : string := L.all;
612	        begin
613	            deallocate(L);
614	            return s;
615	        end function;
616	    begin
617	        file_open(f, filename, read_mode);
618	        
619	        -- Skip any metadata lines
620	        skip_lines(f, skip);
621	        
622	        if not endfile(f) then
623	            -- Just read the first data line of the file
624	            readline(f, L);
625	            file_close(f);
626	            return get_ascii_columns(get_string, mode);
627	        else
628	            -- File is empty
629	            file_close(f);
630	            return 0;
631	        end if;
632	        
633	    end function;
