637	    -----------------------------------------------------------------------------------------------
638	    
639	    -- PROCEDURE READ(LINE)
640	    procedure read(
641	        variable L          : inout line;
642	        variable x          : out   ieee.numeric_bit.signed;
643	        constant mode       : in    text_data_mode_t := ascii_dec
644	    ) is
645	    begin
646	        case mode is
647	            when ascii_bin => ieee.numeric_bit.read(L, x);
648	            when ascii_dec => dread(L, x);
649	            when ascii_hex => hread_safe(L, x);
650	            when others => report "Unsupported mode " & to_string(mode) severity Failure;
651	        end case;
652	    end procedure;
653	    
654	    procedure read(
655	        variable L          : inout line;
656	        variable x          : out   ieee.numeric_bit.unsigned;
657	        constant mode       : in    text_data_mode_t := ascii_dec
658	    ) is
659	    begin
660	        case mode is
661	            when ascii_bin => ieee.numeric_bit.read(L, x);
662	            when ascii_dec => dread(L, x);
663	            when ascii_hex => hread(L, x);
664	            when others => report "Unsupported mode " & to_string(mode) severity Failure;
665	        end case;
666	    end procedure;
667	    
