671	        constant mode       : in    text_data_mode_t := ascii_dec
672	    ) is
673	    begin
674	        case mode is
675	            when ascii_bin => ieee.numeric_std.read(L, x);
676	            when ascii_dec => dread(L, x);
677	            when ascii_hex => hread_safe(L, x);
678	            when others => report "Unsupported mode " & to_string(mode) severity Failure;
679	        end case;
680	    end procedure;
