690	            when ascii_dec => dread(L, x);
691	            when ascii_hex => hread(L, x);
692	            when others => report "Unsupported mode " & to_string(mode) severity Failure;
693	        end case;
694	    end procedure;
695	    
696	    procedure read(
697	        variable L          : inout line;
698	        variable x          : out   integer;
699	        constant mode       : in    text_data_mode_t := ascii_dec
700	    ) is
701	        variable v  : ieee.numeric_bit.signed(31 downto 0);
702	    begin
703	        read(L, v, mode);
704	        x := ieee.numeric_bit.to_integer(v);
705	    end procedure;
706	    
707	    -- Non-numeric types must explicitly indicate signedness
708	    procedure read(
709	        variable L          : inout line;
710	        variable x          : out   bit_vector;
711	        constant signedness : in    Signedness_t;
712	        constant mode       : in    text_data_mode_t := ascii_dec
713	    ) is
714	        variable xu_v       : ieee.numeric_bit.unsigned(x'range);
715	        variable xs_v       : ieee.numeric_bit.signed(x'range);
716	    begin
717	        if signedness = Signed_s then
718	            read(L, xs_v, mode);
719	            x := bit_vector(xs_v);
720	        else
721	            read(L, xu_v, mode);
722	            x := bit_vector(xu_v);
723	        end if;
724	    end procedure;
725	    
726	    procedure read(
727	        variable L          : inout line;
728	        variable x          : out   ieee.std_logic_1164.std_logic_vector;
729	        constant signedness : in    Signedness_t;
730	        constant mode       : in    text_data_mode_t := ascii_dec
731	    ) is
732	        variable xu_v       : ieee.numeric_std.unsigned(x'range);
733	        variable xs_v       : ieee.numeric_std.signed(x'range);
734	    begin
