1046	    -- FUNCTION READ_FILE(FILENAME)
1047	    impure function read_file(
1048	        constant filename   : in  string;
1049	        constant n_bits     : in  positive;
1050	        constant mode       : in  text_data_mode_t := ascii_dec;
1051	        constant skip       : in  natural := 1
1052	    ) return SignedBitArray_t is
1053	        constant n_rows_c   : natural  := get_file_size_lines(filename) - skip;
1054	        constant n_cols_c   : natural  := get_file_size_columns(filename, skip, mode);
1055	        
1056	        file f              : text;
1057	        variable line_v     : line;
1058	        variable data_v     : SignedBitArray_t(0 to n_rows_c*n_cols_c-1)(n_bits-1 downto 0);
1059	    begin
1060	        file_open(f, filename, read_mode);
1061	        
1062	        -- Skip header lines
1063	        skip_lines(f, skip);
1064	        
1065	        for i in 0 to n_rows_c-1 loop
1066	            assert not endfile(f) 
1067	                report "Unexpected end of file after " & integer'image(i) & " lines"
1068	                severity Failure;
1069	                
1070	            readline(f, line_v);
1071	            
1072	            for j in 0 to n_cols_c-1 loop
1073	                assert line_v.all'length > 0
1074	                    report "Unexpected end of line (line " & integer'image(i) & ", column " & integer'image(j) & ")"
1075	                    severity Failure;
1076	                
1077	                read(line_v, data_v(i*n_cols_c + j), mode);
1078	            end loop;
1079	        end loop;
1080	        
1081	        -- Close the file
1082	        file_close(f);
1083	        
1084	        return data_v;
1085	    end function;
