1316	                    report "Unexpected end of line (line " & integer'image(i) & ", column " & integer'image(j) & ")"
1317	                    severity Failure;
1318	                
1319	                read(line_v, data_v(i*n_cols_c + j), signedness, mode);
1320	            end loop;
1321	        end loop;
1322	        
1323	        -- Close the file
1324	        file_close(f);
1325	        
1326	        return data_v;
1327	    end function;
1328	    
1329	    impure function read_file(
1330	        constant filename   : in  string;
1331	        constant n_bits     : in  positive;
1332	        constant signedness : in  Signedness_t;
1333	        constant mode       : in  text_data_mode_t := ascii_dec;
1334	        constant skip       : in  natural := 1
1335	    ) return SulvArray_t is
1336	        constant n_rows_c   : positive := get_file_size_lines(filename) - skip;
1337	        constant n_cols_c   : positive := get_file_size_columns(filename, skip, mode);
1338	        
1339	        file f              : text;
1340	        variable line_v     : line;
1341	        variable data_v     : SulvArray_t(0 to n_rows_c*n_cols_c-1)(n_bits-1 downto 0);
1342	    begin
1343	        file_open(f, filename, read_mode);
1344	        
1345	        -- Skip header lines
1346	        skip_lines(f, skip);
1347	        
1348	        for i in 0 to n_rows_c-1 loop
1349	            assert not endfile(f) 
1350	                report "Unexpected end of file after " & integer'image(i) & " lines"
1351	                severity Failure;
1352	                
1353	            readline(f, line_v);
1354	            
1355	            for j in 0 to n_cols_c-1 loop
1356	                assert line_v.all'length > 0
1357	                    report "Unexpected end of line (line " & integer'image(i) & ", column " & integer'image(j) & ")"
1358	                    severity Failure;
1359	                
1360	                read(line_v, data_v(i*n_cols_c + j), signedness, mode);
1361	            end loop;
1362	        end loop;
1363	        
1364	        -- Close the file
1365	        file_close(f);
1366	        
1367	        return data_v;
1368	    end function;
1369	    
1370	    -----------------------------------------------------------------------------------------------
1371	    -- Write Access
1372	    -----------------------------------------------------------------------------------------------
1373	    
1374	    -- PROCEDURE WRITE(LINE)
1375	    procedure write(
1376	        variable L          : inout line;
1377	        constant x          : in    ieee.numeric_bit.signed;
1378	        constant mode       : in    text_data_mode_t := ascii_dec
1379	    ) is
1380	    begin
1381	        case mode is
1382	            when ascii_bin => ieee.numeric_bit.write(L, x);
1383	            when ascii_dec => dwrite(L, x);
1384	            when ascii_hex => hwrite(L, x);
1385	            when others => report "Unsupported mode " & to_string(mode) severity Failure;
1386	        end case;
1387	    end procedure;
