        case mode is
            when ascii_bin => ieee.numeric_bit.write(L, x);
            when ascii_dec => dwrite(L, x);
            when ascii_hex => hwrite(L, x);
            when others => report "Unsupported mode " & to_string(mode) severity Failure;
        end case;
    end procedure;

